require"UI.UIBase"require"UI.UIBlock"UI_UnbindPhone=UIBase:Inherit()function UI_UnbindPhone:OnCreate()self.regist_mima:GetComponent(typeof(UnityEngine.UI.InputField)).onEndEdit:AddListener(function(a)self:CheckMima1(a)end)self.regist_account:GetComponent(typeof(UnityEngine.UI.InputField)).onEndEdit:AddListener(function(a)self:CheckAccount(a)end)self.verify_code:GetComponent(typeof(UnityEngine.UI.InputField)).onEndEdit:AddListener(function(a)self:CheckVerifyCode(a)end)self.locking=false;self.during_send_cd=false;self.last_send_time=-1;self.timerMgr=TimerMgr:Init()end;function UI_UnbindPhone:OnShow(b,c)if self.locking then return end;self.locking=true;self.callback=c;self.transform.gameObject:SetActive(true)self:AnimPopOut(self.transform:Find('root'),function()b()self.locking=false end)self.timerMgr:ClearAllTimers()if not self.during_send_cd then self.btn_send_verify.interactable=true;self.verify_code_desc.text=Tools.StrOfLocalization(2787)else self:_refresh_send()end;self.timerMgr:LoopFrame(1,-1,function()self:_refresh_send()end)self:CheckInformation()end;function UI_UnbindPhone:Hide(d)if self.locking then return end;self.locking=true;self:AnimPopHide(self.transform:Find('root'),function()self.locking=false;UnityEngine.GameObject.Destroy(self.transform.gameObject)self.timerMgr:ClearAllTimers()if self.callback and not d then self.callback({success=true})elseif self.callback and d then self.callback({success=false})end end)end;function UI_UnbindPhone:CheckAccount(a)if#a==0 then self.no_account.transform.gameObject:SetActive(false)self.yes_account.transform.gameObject:SetActive(false)else if not Tools.pending_phonenumber_valid(a)then self.no_account.transform.gameObject:SetActive(true)self.yes_account.transform.gameObject:SetActive(false)self.is_account_valid=false else self.no_account.transform.gameObject:SetActive(false)self.yes_account.transform.gameObject:SetActive(true)self.is_account_valid=true end end;self:CheckInformation()end;function UI_UnbindPhone:CheckVerifyCode(a)if Tools.GetStringLength(a)==6 then self.no_verifycode.transform.gameObject:SetActive(false)self.yes_verifycode.transform.gameObject:SetActive(true)elseif Tools.GetStringLength(a)~=0 then self.yes_verifycode.transform.gameObject:SetActive(false)self.no_verifycode.transform.gameObject:SetActive(true)else self.yes_verifycode.transform.gameObject:SetActive(false)self.no_verifycode.transform.gameObject:SetActive(false)end;self:CheckInformation()end;function UI_UnbindPhone:CheckMima1(a)if#a==0 then self.no_mima.transform.gameObject:SetActive(false)self.yes_mima.transform.gameObject:SetActive(false)else if#a<6 then self.no_mima.transform.gameObject:SetActive(true)self.yes_mima.transform.gameObject:SetActive(false)else self.no_mima.transform.gameObject:SetActive(false)self.yes_mima.transform.gameObject:SetActive(true)end end;self:CheckInformation()end;function UI_UnbindPhone:_refresh_send()if not self.during_send_cd then return end;local e=UnityEngine.Time.time-self.last_send_time;if e>=60 then self.during_send_cd=false;self.btn_send_verify.interactable=true;self.verify_code_desc.text=Tools.StrOfLocalization(2787)else self.btn_send_verify.interactable=false;self.verify_code_desc.text=Tools.StrOfLocalization(2682,tostring(Mathf.Ceil(60-e)))end end;function UI_UnbindPhone:Btn_SendVerify()if self.locking then return end;if not self.is_account_valid then UIMgr.Inst:ShowUI(UI_ErrorInfo.className,nil,{errorType=UI_ErrorInfo.ErrorType.Normal,msg=Tools.StrOfLocalization(2786)})self.no_account.transform.gameObject:SetActive(true)self.yes_account.transform.gameObject:SetActive(false)return else local f=self.regist_account:GetComponent(typeof(UnityEngine.UI.InputField)).text;self.during_send_cd=true;self.last_send_time=UnityEngine.Time.time;self:_refresh_send()local g=ProtoMgr.CreateRequest('Lobby','createPhoneVerifyCode')g.phone=f;g.usage=8;LobbyNetMgr.SendRequest('Lobby','createPhoneVerifyCode',g,function(h,i)if h or i.error and i.error.code~=0 then UIMgr.Inst:ShowUI(UI_Erro